'use client'

import { useState } from 'react'

export default function EMICalculator() {
  const [loan, setLoan] = useState('')
  const [rate, setRate] = useState('')
  const [tenure, setTenure] = useState('')
  const [emi, setEmi] = useState<number | null>(null)

  function calculate() {
    const P = parseFloat(loan || '0')
    const r = parseFloat(rate || '0') / 12 / 100
    const n = parseFloat(tenure || '0') * 12
    if (!P || !n) return setEmi(0)
    if (r === 0) return setEmi(P / n)
    const x = Math.pow(1 + r, n)
    const E = (P * r * x) / (x - 1)
    setEmi(E)
  }

  function reset() {
    setLoan('')
    setRate('')
    setTenure('')
    setEmi(null)
  }

  return (
    <main className="container mx-auto p-4">
      <h1 className="text-2xl font-bold">EMI Calculator</h1>
      <div className="mt-4 max-w-md">
        <label className="block">
          <span>Loan Amount (₹)</span>
          <input value={loan} onChange={e => setLoan(e.target.value)} className="w-full p-2 border rounded mt-1" />
        </label>

        <label className="block mt-3">
          <span>Annual Interest Rate (%)</span>
          <input value={rate} onChange={e => setRate(e.target.value)} className="w-full p-2 border rounded mt-1" />
        </label>

        <label className="block mt-3">
          <span>Tenure (years)</span>
          <input value={tenure} onChange={e => setTenure(e.target.value)} className="w-full p-2 border rounded mt-1" />
        </label>

        <div className="flex gap-2 mt-4">
          <button onClick={calculate} className="px-4 py-2 bg-blue-600 text-white rounded">Calculate</button>
          <button onClick={reset} className="px-4 py-2 border rounded">Reset</button>
        </div>

        {emi !== null && (
          <div className="mt-4 p-4 bg-slate-50 dark:bg-slate-800 rounded">
            <div className="font-semibold">Monthly EMI</div>
            <div className="text-2xl">₹ {emi.toFixed(2)}</div>
            <div className="mt-2 flex gap-2">
              <button className="px-3 py-1 bg-slate-200 rounded">Copy</button>
              <button className="px-3 py-1 border rounded">Share</button>
            </div>
          </div>
        )}
      </div>
    </main>
  )
}
